import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Roles & Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/roles-permissions.md","filePath":"guide/roles-permissions.md"}'),o={name:"guide/roles-permissions.md"};function i(s,t,n,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="roles-permissions" tabindex="-1">Roles &amp; Permissions <a class="header-anchor" href="#roles-permissions" aria-label="Permalink to &quot;Roles &amp; Permissions&quot;">​</a></h1><p>GeniusHRM uses a role-based access control (RBAC) system. Every user is assigned one role, and each role has a set of permissions that determine which areas and actions they can access.</p><hr><h2 id="built-in-roles" tabindex="-1">Built-in Roles <a class="header-anchor" href="#built-in-roles" aria-label="Permalink to &quot;Built-in Roles&quot;">​</a></h2><p>Six roles ship with GeniusHRM out of the box. They cannot be deleted, but their permissions can be customised.</p><table tabindex="0"><thead><tr><th>Role</th><th>Primary Purpose</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Full system access — no restrictions</td></tr><tr><td><strong>HR Manager</strong></td><td>Manages all HR operations</td></tr><tr><td><strong>Manager</strong></td><td>Department-level oversight</td></tr><tr><td><strong>Employee</strong></td><td>Self-service access to own data</td></tr><tr><td><strong>Recruiter</strong></td><td>Manages recruitment pipeline</td></tr><tr><td><strong>Finance</strong></td><td>Payroll and compensation management</td></tr></tbody></table><hr><h2 id="role-permissions-matrix" tabindex="-1">Role Permissions Matrix <a class="header-anchor" href="#role-permissions-matrix" aria-label="Permalink to &quot;Role Permissions Matrix&quot;">​</a></h2><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Employees</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Organization</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Attendance</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Leave</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Payroll</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Recruitment</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Performance</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Training</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Documents</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Reports</td><td>✅</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Settings</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Users</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="hr-manager" tabindex="-1">HR Manager <a class="header-anchor" href="#hr-manager" aria-label="Permalink to &quot;HR Manager&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Employees</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Organization</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Attendance</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Leave</td><td>✅</td><td>✅</td><td>✅ (approve/reject)</td><td>❌</td></tr><tr><td>Payroll</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Recruitment</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Performance</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Training</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Documents</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Reports</td><td>✅</td><td>—</td><td>—</td><td>—</td></tr><tr><td>Settings</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Users</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><h3 id="manager" tabindex="-1">Manager <a class="header-anchor" href="#manager" aria-label="Permalink to &quot;Manager&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Employees (dept)</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Attendance (dept)</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Leave (direct reports)</td><td>✅</td><td>❌</td><td>✅ (approve/reject)</td><td>❌</td></tr><tr><td>Performance (direct reports)</td><td>✅</td><td>❌</td><td>✅ (scoring)</td><td>❌</td></tr><tr><td>Reports (dept)</td><td>✅</td><td>—</td><td>—</td><td>—</td></tr></tbody></table><h3 id="employee" tabindex="-1">Employee <a class="header-anchor" href="#employee" aria-label="Permalink to &quot;Employee&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Own Profile</td><td>✅</td><td>❌</td><td>✅ (limited)</td><td>❌</td></tr><tr><td>Own Attendance</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Leave Requests</td><td>✅ (own)</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>Own Payslips</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Own Performance</td><td>✅</td><td>❌</td><td>✅ (self-assessment)</td><td>❌</td></tr><tr><td>Training (enroll)</td><td>✅</td><td>✅ (enroll self)</td><td>❌</td><td>❌</td></tr><tr><td>Own Documents</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><h3 id="recruiter" tabindex="-1">Recruiter <a class="header-anchor" href="#recruiter" aria-label="Permalink to &quot;Recruiter&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Recruitment</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Employees</td><td>✅ (view only)</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table><h3 id="finance" tabindex="-1">Finance <a class="header-anchor" href="#finance" aria-label="Permalink to &quot;Finance&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>View</th><th>Create</th><th>Edit</th><th>Delete</th></tr></thead><tbody><tr><td>Payroll</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Employees</td><td>✅ (view only)</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Reports (payroll)</td><td>✅</td><td>—</td><td>—</td><td>—</td></tr></tbody></table><hr><h2 id="creating-a-custom-role" tabindex="-1">Creating a Custom Role <a class="header-anchor" href="#creating-a-custom-role" aria-label="Permalink to &quot;Creating a Custom Role&quot;">​</a></h2><p>In addition to the six built-in roles, administrators can create custom roles with precisely controlled permissions.</p><ol><li>Navigate to <strong>Admin Panel → Roles</strong></li><li>Click <strong>Add Role</strong></li><li>Enter a <strong>Role Name</strong> (e.g., <code>Payroll Analyst</code>)</li><li>In the permissions matrix, toggle individual permissions: <ul><li>Each module row has columns: <code>View</code>, <code>Create</code>, <code>Edit</code>, <code>Delete</code></li><li>Check only the permissions this role should have</li></ul></li><li>Click <strong>Save Role</strong></li><li>Assign the new role to users via <strong>Users → Edit User → Role</strong></li></ol><h3 id="available-permissions-per-module" tabindex="-1">Available Permissions per Module <a class="header-anchor" href="#available-permissions-per-module" aria-label="Permalink to &quot;Available Permissions per Module&quot;">​</a></h3><p>Each module exposes granular permissions:</p><table tabindex="0"><thead><tr><th>Permission Key</th><th>Description</th></tr></thead><tbody><tr><td><code>employees.view</code></td><td>View employee list and profiles</td></tr><tr><td><code>employees.create</code></td><td>Add new employees</td></tr><tr><td><code>employees.edit</code></td><td>Edit employee data</td></tr><tr><td><code>employees.delete</code></td><td>Soft-delete employees</td></tr><tr><td><code>payroll.run</code></td><td>Start a payroll cycle</td></tr><tr><td><code>payroll.approve</code></td><td>Approve and finalise payroll</td></tr><tr><td><code>leave.approve</code></td><td>Approve or reject leave requests</td></tr><tr><td><code>performance.finalise</code></td><td>Finalise appraisal ratings</td></tr><tr><td><code>settings.access</code></td><td>Access system settings panel</td></tr><tr><td><code>audit-log.view</code></td><td>View the audit log</td></tr><tr><td>...</td><td>More per module</td></tr></tbody></table><hr><h2 id="permission-inheritance" tabindex="-1">Permission Inheritance <a class="header-anchor" href="#permission-inheritance" aria-label="Permalink to &quot;Permission Inheritance&quot;">​</a></h2><p>Permissions are not inherited between roles. Each role&#39;s permission set is independent. If you need a role that covers multiple job functions, create a custom role and select all required permissions explicitly.</p><hr><h2 id="checking-your-own-permissions" tabindex="-1">Checking Your Own Permissions <a class="header-anchor" href="#checking-your-own-permissions" aria-label="Permalink to &quot;Checking Your Own Permissions&quot;">​</a></h2><p>Any logged-in user can see what permissions they have by going to <strong>Profile → My Permissions</strong>. This is a read-only view showing which modules and actions are available to their role.</p><hr><h2 id="changing-a-user-s-role" tabindex="-1">Changing a User&#39;s Role <a class="header-anchor" href="#changing-a-user-s-role" aria-label="Permalink to &quot;Changing a User&#39;s Role&quot;">​</a></h2><ol><li>Go to <strong>Admin Panel → Users</strong></li><li>Click <strong>Edit</strong> on the target user</li><li>Change the <strong>Role</strong> dropdown to the desired role</li><li>Click <strong>Update User</strong></li></ol><p>The new permissions take effect immediately. Active sessions are updated on the next page load.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Downgrading a user&#39;s role (e.g., from Admin to Employee) takes effect immediately. If the user is currently logged in, they will lose access to restricted areas on their next navigation.</p></div>',38)])])}const u=d(o,[["render",i]]);export{p as __pageData,u as default};
